import { useTranslation } from "react-i18next";

// Map country names to their primary language suffix in the database
const COUNTRY_LANG_MAP: Record<string, string> = {
  "Portugal": "pt", "Brazil": "pt", "Mozambique": "pt", "Angola": "pt",
  "China": "zh", "Taiwan": "zh", "Hong Kong": "zh", "Macau": "zh",
  "Spain": "es", "Mexico": "es", "Argentina": "es", "Colombia": "es", "Chile": "es", "Peru": "es",
  "France": "fr", "Belgium": "fr", "Switzerland": "fr",
  "Germany": "de", "Austria": "de",
  "Italy": "it",
  "Japan": "ja",
  "South Korea": "ko", "Korea": "ko",
  "Russia": "ru",
  "Saudi Arabia": "ar", "UAE": "ar", "United Arab Emirates": "ar",
  "United States": "en", "United Kingdom": "en", "Australia": "en", "Canada": "en",
  "Netherlands": "en", "Sweden": "en", "Norway": "en", "Denmark": "en", "Finland": "en",
};

/** Infer the native language of a data item based on its country field */
function getItemNativeLang(item: Record<string, any>): string | null {
  const country = item.country || item.country_name;
  if (!country) return null;
  return COUNTRY_LANG_MAP[country] || null;
}

export const useLocalizedContent = () => {
  const { i18n } = useTranslation();
  const currentLang = i18n.language;

  /**
   * Unified fallback chain (ZH as primary source):
   * 1. Exact lang suffix (e.g., field_fr)
   * 2. translations JSONB cache
   * 3. Frozen _en/_pt fields (existing high-quality translations)
   * 4. Item's native language field
   * 5. Base field (original/ZH)
   */
  const getLocalizedField = <T extends Record<string, any>>(
    item: T,
    fieldName: string
  ): any => {
    let value;
    
    // 1. Try exact language suffix (e.g., _fr, _es, _de, _ja, _ko, _it, _ru, _ar)
    const langField = `${fieldName}_${currentLang}`;
    value = item[langField];
    
    // 2. Check translations JSONB column for on-demand translations
    if (!value && item.translations && typeof item.translations === 'object') {
      const translations = item.translations as Record<string, any>;
      if (translations[currentLang] && translations[currentLang][fieldName]) {
        value = translations[currentLang][fieldName];
      }
    }
    
    // 3. Smart fallback: try frozen _en/_pt, then item's native language, then base field
    if (!value) {
      if (currentLang === "zh") {
        // Chinese users: base field is already Chinese
        value = item[`${fieldName}_zh`] || item[fieldName];
      } else {
        // Try frozen _en/_pt fields first
        if (currentLang !== "en") {
          value = item[`${fieldName}_en`];
        }
        if (!value && currentLang !== "pt") {
          value = item[`${fieldName}_pt`];
        }
        // Try the item's native language
        if (!value) {
          const nativeLang = getItemNativeLang(item);
          if (nativeLang && nativeLang !== currentLang) {
            value = item[`${fieldName}_${nativeLang}`];
          }
        }
        // Fall back to EN, then base field
        if (!value) {
          value = item[`${fieldName}_en`] || item[fieldName];
        }
      }
    }
    
    // For name and title fields, if it's an array, join it
    if ((fieldName === "name" || fieldName === "title" || fieldName.startsWith("title_")) && Array.isArray(value)) {
      return value.join(", ");
    }
    
    // Return as-is if it's already an array or other type
    return value || "";
  };

  /**
   * Get dual-name display for restaurants: "TranslatedName · OriginalName"
   * Returns { displayName, originalName, showDual }
   */
  const getNameWithOriginal = (item: Record<string, any>): {
    displayName: string;
    originalName: string;
    showDual: boolean;
  } => {
    const originalName = String(item.name || "");
    const translatedName = getLocalizedField(item, "name");
    
    // Determine if names differ (need dual display)
    const normalizedOriginal = originalName.trim().toLowerCase();
    const normalizedTranslated = String(translatedName).trim().toLowerCase();
    const showDual = normalizedOriginal !== normalizedTranslated && !!normalizedOriginal && !!normalizedTranslated;
    
    return {
      displayName: translatedName || originalName,
      originalName,
      showDual,
    };
  };

  const localizeRestaurant = (restaurant: any) => {
    return {
      ...restaurant,
      name: getLocalizedField(restaurant, "name"),
      type: getLocalizedField(restaurant, "type"),
      description: getLocalizedField(restaurant, "description"),
    };
  };

  const localizeActivity = (activity: any) => {
    return {
      ...activity,
      title: getLocalizedField(activity, "title"),
      intro: getLocalizedField(activity, "intro"),
      content: getLocalizedField(activity, "content"),
      usage_instructions: getLocalizedField(activity, "usage_instructions"),
    };
  };

  const localizePost = (post: any) => {
    return {
      ...post,
      content: getLocalizedField(post, "content"),
    };
  };

  // Helper to format type array as string for display
  const getLocalizedTypeString = (restaurant: any): string => {
    const typeValue = restaurant.type;
    if (Array.isArray(typeValue)) {
      return typeValue.join(" · ");
    }
    return typeValue || "";
  };

  return {
    getLocalizedField,
    getNameWithOriginal,
    localizeRestaurant,
    localizeActivity,
    localizePost,
    getLocalizedTypeString,
    currentLang,
  };
};
